(function(){var e=`toudiya-app`;window.addEventListener(`message`,t=>{t.source!==window||t.origin!==window.location.origin||t.data?.source===e&&(t.data?.type!==`TOUDIYA_EXTENSION_TOKEN`||!t.data.token||chrome.runtime.sendMessage({type:`PAIRING_TOKEN_RECEIVED`,token:t.data.token}).then(()=>{window.postMessage({source:e,type:`TOUDIYA_EXTENSION_ACK`},window.location.origin)}).catch(e=>{console.error(`[toudiya-extension] 配对失败：`,e)}))});})()
